#!/usr/bin/env python3
"""Call `interface_pocket_consensus` on a fresh input. Auto-generated by Lazarus.

Self-contained: needs only Docker. Works the same against a LOCAL daemon or a
REMOTE one (export DOCKER_HOST=ssh://user@host) — the input and outputs are
copied with `docker cp`, not bind-mounted, so it runs identically on a laptop,
a lab workstation, or a cloud/x86 box.

    python predict.py <input> <output_dir>
"""
import subprocess
import sys
import uuid
from pathlib import Path

IMAGE = "python:3.11-slim"
PLATFORM = "linux/amd64"
GPUS = None  # e.g. "all" to pass GPUs (needs nvidia-container-toolkit), or None
# In-container command template; $INPUT and $OUTDIR are substituted at runtime.
ENTRYPOINT = "set -euo pipefail\npip install --quiet numpy >/dev/null 2>&1 || pip install --quiet --break-system-packages numpy >/dev/null 2>&1\nmkdir -p \"$OUTDIR\"\npython - <<'PY'\nimport os, csv, json\nimport numpy as np\n\ndef get(d, *keys, default=None):\n    for k in keys:\n        if k in d: return d[k]\n    return default\n\n# ScanNet: per-residue CSV\nscannet = {}\nwith open(os.environ[\"scannet\"]) as f:\n    for row in csv.DictReader(f):\n        if row.get(\"Chain\", \"A\").strip() == \"A\":\n            scannet[int(row[\"Residue Index\"])] = float(row[\"Binding site probability\"])\n\n# dMaSIF: per-residue npy (ids + scores)\nd_ids = np.load(os.environ[\"dmasif_ids\"])\nd_scores = np.load(os.environ[\"dmasif_scores\"])\ndmasif = {int(r): float(s) for r, s in zip(d_ids, d_scores)}\n\n# fpocket: pockets.json -> per-residue best druggability over ANY pocket\npockets = json.load(open(os.environ[\"pockets\"]))\nif isinstance(pockets, dict):\n    pockets = get(pockets, \"pockets\", default=[])\nDRUG = 0.5\npocket_res = {}\npocket_list = []\nfor p in pockets:\n    score = float(get(p, \"druggability\", \"drug_score\", \"druggability_score\", default=0) or 0)\n    resids_p = []\n    for r in get(p, \"lining_residues\", \"residues\", \"resids\", default=[]) or []:\n        try:\n            resids_p.append(int(r))\n        except (ValueError, TypeError):\n            pass\n    pocket_list.append((get(p, \"rank\", \"pocket\", default=len(pocket_list) + 1), score, len(resids_p)))\n    for rid in resids_p:\n        pocket_res[rid] = max(pocket_res.get(rid, 0.0), score)\nn_drug_pockets = sum(1 for _, s, _ in pocket_list if s >= DRUG)\ntop_drug = max((s for _, s, _ in pocket_list), default=0.0)\n\n# per-residue consensus\nresids = sorted(set(scannet) | set(dmasif))\nrows = []\nfor r in resids:\n    sn, dm = scannet.get(r), dmasif.get(r)\n    vals = [x for x in (sn, dm) if x is not None]\n    site = float(np.mean(vals)) if vals else 0.0\n    pd = pocket_res.get(r, 0.0)\n    rows.append((r, sn, dm, site, pd >= DRUG, pd))\nrows.sort(key=lambda x: -x[3])\n\nout = os.environ[\"OUTDIR\"]\nwith open(os.path.join(out, \"triage.csv\"), \"w\", newline=\"\") as f:\n    w = csv.writer(f)\n    w.writerow([\"resid\", \"scannet\", \"dmasif\", \"consensus_site\", \"in_druggable_pocket\", \"pocket_druggability\"])\n    for row in rows:\n        w.writerow([\"\" if v is None else v for v in row])\n\niface = [r for r in rows if r[3] >= 0.5]\niface_pocket = [r for r in iface if r[5] > 0]\nhot = [r for r in iface if r[4]]\nwith open(os.path.join(out, \"summary.txt\"), \"w\") as f:\n    f.write(\"Binder-interface triage\\n\")\n    f.write(\"=======================\\n\")\n    f.write(f\"residues scored (ScanNet + dMaSIF consensus) : {len(rows)}\\n\")\n    f.write(f\"predicted interface residues (consensus >= 0.5): {len(iface)}\\n\")\n    f.write(\"  top: \" + \", \".join(str(r[0]) for r in iface[:12]) + \"\\n\")\n    f.write(f\"fpocket pockets found: {len(pockets)} (top druggability {top_drug:.2f})\\n\")\n    f.write(f\"interface residues that coincide with a pocket : {len(iface_pocket)}\"\n            f\" (max pocket druggability {max((r[5] for r in iface_pocket), default=0):.2f})\\n\")\n    f.write(f\"HOT small-molecule targets (interface AND druggability >= {DRUG}): {len(hot)}\\n\\n\")\n    if hot:\n        f.write(\"=> Candidate druggable small-molecule site(s) at the interface:\\n\")\n        for r in hot[:20]:\n            f.write(f\"     resid {r[0]:>4}: site={r[3]:.2f}  pocket_druggability={r[5]:.2f}\\n\")\n    else:\n        f.write(\"=> The interface is clearly localized but is NOT a druggable small-molecule\\n\"\n                \"   pocket (top druggability {:.2f} < {:.1f}). This is the signature of a flat\\n\"\n                \"   protein-protein interface -> an antibody / biologic target, not a small\\n\"\n                \"   molecule one.\\n\".format(top_drug, DRUG))\nprint(f\"triage_residues={len(rows)} pockets={len(pockets)} interface={len(iface)} hot={len(hot)}\")\nPY\n"


def _run(*argv, check=True):
    return subprocess.run(list(argv), check=check)


def predict(input_path: str, output_dir: str) -> None:
    inp = Path(input_path).resolve()
    out = Path(output_dir).resolve()
    out.mkdir(parents=True, exist_ok=True)
    cmd = ENTRYPOINT.replace("$INPUT", "/io/in/" + inp.name).replace("$OUTDIR", "/io/out")
    name = "lazarus-predict-" + uuid.uuid4().hex[:10]
    run_args = ["docker", "run", "-d", "--name", name, "--platform", PLATFORM]
    if GPUS:
        run_args += ["--gpus", GPUS]
    run_args += [IMAGE, "sleep", "infinity"]
    _run(*run_args)
    try:
        _run("docker", "exec", name, "mkdir", "-p", "/io/in", "/io/out")
        _run("docker", "cp", str(inp), f"{name}:/io/in/{inp.name}")
        _run("docker", "exec", name, "bash", "-lc", cmd)
        _run("docker", "cp", f"{name}:/io/out/.", str(out))
    finally:
        _run("docker", "rm", "-f", name, check=False)
    print(f"outputs written to {out}")


if __name__ == "__main__":
    if len(sys.argv) != 3:
        sys.exit("usage: python predict.py <input> <output_dir>")
    predict(sys.argv[1], sys.argv[2])
